async function resolveMetaToken() {
  try {
    const fad = await this.getCredentials('facebookLeadAdsOAuth2Api');
    const t = String(fad.oauthTokenData?.access_token || fad.accessToken || fad.access_token || '').trim();
    if (t) return t;
  } catch (_) {}
  try {
    const fb = await this.getCredentials('facebookGraphApi');
    const t = String(fb.accessToken || fb.access_token || '').trim();
    if (t) return t;
  } catch (_) {}
  const sd = $getWorkflowStaticData('global');
  if (sd.metaAccessToken) return String(sd.metaAccessToken).trim();
  return String($env.META_PAGE_ACCESS_TOKEN || $env.META_ACCESS_TOKEN || '').trim();
}
const META_TOKEN = await resolveMetaToken.call(this);
const GRAPH = $getWorkflowStaticData('global').metaGraphVersion || $env.META_GRAPH_VERSION || 'v21.0';
const MAX = Math.min(500, Math.max(1, Number($getWorkflowStaticData('global').metaLeadsMaxPerRun || $env.META_LEADS_MAX_PER_RUN || 100)));

if (!META_TOKEN) {
  throw new Error('ربط Meta: Credentials → Facebook Lead Ads OAuth2 API (أو Facebook Graph API) على عقدة Fetch Meta Leads ثم Connect');
}

function parseFieldData(fieldData) {
  const map = {};
  if (!Array.isArray(fieldData)) return map;
  for (const row of fieldData) {
    const n = String(row?.name || '').toLowerCase().replace(/\s+/g, '_');
    const v = Array.isArray(row?.values) && row.values[0] != null ? String(row.values[0]).trim() : '';
    if (n && v) map[n] = v;
  }
  const email = map.email || map.work_email || map.business_email || map['e-mail'] || '';
  const phone = map.phone_number || map.phone || map.mobile || map.mobile_phone || map.work_phone || '';
  const fullName =
    map.full_name ||
    (map.first_name || map.last_name ? `${map.first_name || ''} ${map.last_name || ''}`.trim() : '') ||
    map.name ||
    '';
  const company = map.company_name || map.company || map.business_name || map.organization || '';
  return { email, phone, fullName, company };
}

function resolveSource(platform, pageName, formName) {
  const p = String(platform || '').toLowerCase();
  if (p === 'ig' || p === 'instagram' || p.includes('instagram')) return 'instagram';
  if (p === 'fb' || p === 'facebook') return 'facebook';
  const blob = `${pageName || ''} ${formName || ''}`.toLowerCase();
  if (/instagram|\binsta\b|\big\b/.test(blob)) return 'instagram';
  return 'facebook';
}

async function graphGet(url) {
  return await this.helpers.httpRequest({ method: 'GET', url, json: true, timeout: 60000 });
}

async function fetchAllLeads(formId, pageToken, remaining) {
  const leads = [];
  let url = `https://graph.facebook.com/${GRAPH}/${formId}/leads?fields=id,created_time,field_data,platform&limit=50&access_token=${encodeURIComponent(pageToken)}`;
  while (url && leads.length < remaining) {
    const res = await graphGet.call(this, url);
    for (const row of res.data || []) {
      leads.push(row);
      if (leads.length >= remaining) break;
    }
    url = leads.length < remaining && res.paging?.next ? res.paging.next : null;
  }
  return leads;
}

const pagesRes = await graphGet.call(
  this,
  `https://graph.facebook.com/${GRAPH}/me/accounts?fields=id,name,access_token&limit=50&access_token=${encodeURIComponent(META_TOKEN)}`,
);

const pages = pagesRes.data || [];
const out = [];
let graphErrors = 0;

for (const page of pages) {
  if (!page.access_token) continue;
  let formsRes;
  try {
    formsRes = await graphGet.call(
      this,
      `https://graph.facebook.com/${GRAPH}/${page.id}/leadgen_forms?fields=id,name,status&limit=40&access_token=${encodeURIComponent(page.access_token)}`,
    );
  } catch {
    graphErrors += 1;
    continue;
  }

  for (const form of formsRes.data || []) {
    let rows;
    try {
      rows = await fetchAllLeads.call(this, form.id, page.access_token, MAX - out.length);
    } catch {
      graphErrors += 1;
      continue;
    }

    for (const row of rows) {
      const parsed = parseFieldData(row.field_data);
      const metaId = String(row.id);
      let email = (parsed.email || '').toLowerCase().trim();
      let phone = (parsed.phone || '').replace(/\s+/g, '').trim();
      const name = ((parsed.fullName || '').trim() || 'عميل إعلان').slice(0, 200);
      const company = ((parsed.company || page.name || '—').trim() || '—').slice(0, 200);

      if (!email && !phone) email = `lead-${metaId}@meta-lead.local`;
      if (!phone) phone = '01000000000';
      if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) email = `lead-${metaId}@meta-lead.local`;

      const source = resolveSource(row.platform, page.name, form.name);
      out.push({
        meta_lead_id: metaId,
        name,
        company,
        phone,
        email,
        source,
        page_name: page.name || page.id,
        form_name: form.name || form.id,
        created_time: row.created_time || new Date().toISOString(),
      });
      if (out.length >= MAX) break;
    }
    if (out.length >= MAX) break;
  }
  if (out.length >= MAX) break;
}

if (out.length === 0) {
  return [
    {
      json: {
        _summary: true,
        fetched: 0,
        graph_errors: graphErrors,
        pages: pages.length,
        message: pages.length === 0 ? 'No Facebook pages linked to this token.' : 'No new lead rows from Meta in this run.',
      },
    },
  ];
}

return out.map((item) => ({ json: item }));

async function resolveSupabase() {
  let url = '';
  let key = '';
  try {
    const sb = await this.getCredentials('supabaseApi');
    url = String(sb.host || sb.url || '').replace(/\/$/, '');
    key = String(sb.serviceRole || sb.serviceRoleKey || '').trim();
  } catch (_) {}
  if (!url) url = String($env.SUPABASE_URL || '').replace(/\/$/, '');
  if (!key) key = String($env.SUPABASE_SERVICE_ROLE_KEY || '').trim();
  if (!url || !key) {
    throw new Error('ربط Supabase: اختر Credential نوع Supabase API (Host + Service Role) على عقدة Insert، أو Environment.');
  }
  return { url, key };
}
const { url: SUPABASE_URL, key: KEY } = await resolveSupabase.call(this);
const sd = $getWorkflowStaticData('global');
const ASSIGNED = sd.defaultAssignedToId || $env.DEFAULT_ASSIGNED_TO_ID || null;

const headers = {
  apikey: KEY,
  Authorization: `Bearer ${KEY}`,
  'Content-Type': 'application/json',
};

function makeId() {
  return `lead_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`;
}

const items = $input.all().filter((i) => !i.json._summary);
const results = [];
let inserted = 0;
let skipped = 0;
let errors = 0;

for (const item of items) {
  const lead = item.json;
  const email = lead.email;
  const phone = lead.phone;

  let existing;
  try {
    const checkUrl = `${SUPABASE_URL}/rest/v1/leads?or=(email.eq.${encodeURIComponent(email)},phone.eq.${encodeURIComponent(phone)})&select=id,source&limit=1`;
    existing = await this.helpers.httpRequest({ method: 'GET', url: checkUrl, headers, json: true });
  } catch (e) {
    errors += 1;
    results.push({ json: { ...lead, status: 'error', step: 'duplicate_check', message: e.message } });
    continue;
  }

  if (Array.isArray(existing) && existing.length > 0) {
    skipped += 1;
    results.push({ json: { ...lead, status: 'skipped_duplicate', existing_id: existing[0].id } });
    continue;
  }

  const id = makeId();
  const now = new Date().toISOString();
  const createdAt = lead.created_time || now;
  const timeline = [
    {
      id: `ev-meta-${id}`,
      leadId: id,
      action: `استيراد من n8n (${lead.source})`,
      note: `Meta Lead ID: ${lead.meta_lead_id} — ${lead.page_name} — ${lead.form_name}`,
      userId: 'n8n',
      userName: 'تكامل Meta',
      createdAt,
    },
    {
      id: `a-${id}`,
      leadId: id,
      action: 'إضافة الليد إلى النظام',
      userId: 'n8n',
      userName: 'تكامل Meta',
      createdAt: now,
    },
  ];

  const row = {
    id,
    customer_code: null,
    name: lead.name,
    company: lead.company,
    phone: lead.phone,
    email: lead.email,
    status: 'جديد',
    assigned_to_id: ASSIGNED,
    budget: 0,
    company_size: 'صغير',
    source: lead.source,
    category: 'إعلانات',
    score: 55,
    follow_up_at: null,
    loss_reason_code: null,
    sla_status: 'مستقر',
    timeline_json: timeline,
    created_at: createdAt,
    updated_at: now,
  };

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/leads`,
      headers: { ...headers, Prefer: 'return=minimal' },
      body: row,
    });
    inserted += 1;
    results.push({ json: { ...lead, status: 'inserted', lead_id: id } });
  } catch (e) {
    errors += 1;
    results.push({ json: { ...lead, status: 'error', step: 'insert', message: e.message } });
  }
}

results.push({
  json: {
    _summary: true,
    processed: items.length,
    inserted,
    skipped_duplicate: skipped,
    errors,
  },
});

return results;
